import json
import base64
import pickle
from botocore.vendored import requests

def lambda_handler(event, context):
    message = base64.b64decode(event['body'])
    deserialized = pickle.loads(message) # deserialize the payload using pickle
    
    user_actions = deserialized["userActions"]
    for action in user_actions: 
        print(f"Processing {action}")
        
    return {
       'statusCode': 200,
       'body': json.dumps('Successfully processed the webhook event!')
    }